"""
server.py
Grow Station Pico HTTP server — Microdot-based REST API + static file serving.

Endpoints:
  GET  /                          — serve index.html
  GET  /style.css                 — serve stylesheet
  GET  /app.js                    — serve frontend JS
  GET  /help.html                 — serve help page

  GET  /api/status                — zone moisture, relay states, light states
  POST /api/water                 — manual water { "zone": 0 }

  GET  /api/config                — settings (zones, lights, wifi, version)
  PUT  /api/config                — update settings

  GET  /api/schedules             — light schedules
  PUT  /api/schedules             — update light schedules

  POST /api/update                — OTA: write file to flash
  GET  /api/ota/manifest          — OTA: read installed manifest
  PUT  /api/ota/manifest          — OTA: write installed manifest

  POST /api/light/mode            — set light operational mode (schedule/skip/manual)

  POST /api/wifi/reset            — erase WiFi credentials, reboot to portal
  GET  /api/version               — firmware version
"""

import asyncio
import gc
import json
import os
import time
import machine

from microdot import Microdot, Request

Request.max_content_length = 32 * 1024

import config_manager
import moisture
import watering
import schedule
import relay
from version import FIRMWARE_VERSION, BUILD_DATE

app = Microdot()

_boot_ticks = time.ticks_ms()


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _json(data, status=200):
    body = json.dumps(data)
    return body, status, {"Content-Type": "application/json",
                          "Cache-Control": "no-store"}


def _error(msg, status=400):
    return _json({"error": msg}, status)


def _serve_file(filename, content_type):
    for prefix in ("/web/", "/"):
        path = prefix + filename
        try:
            os.stat(path)
            with open(path, "r") as f:
                body = f.read()
            return body, 200, {"Content-Type": content_type,
                               "Cache-Control": "no-cache"}
        except OSError:
            continue
    return _error("Not found", 404)


def _file_exists(path):
    try:
        os.stat(path)
        return True
    except OSError:
        return False


# ---------------------------------------------------------------------------
# Static files
# ---------------------------------------------------------------------------

@app.route("/", methods=["GET"])
async def index(request):
    return _serve_file("index.html", "text/html; charset=utf-8")


@app.route("/style.css", methods=["GET"])
async def css(request):
    return _serve_file("style.css", "text/css; charset=utf-8")


@app.route("/app.js", methods=["GET"])
async def js(request):
    return _serve_file("app.js", "application/javascript; charset=utf-8")


@app.route("/help.html", methods=["GET"])
async def help_page(request):
    return _serve_file("help.html", "text/html; charset=utf-8")


@app.route("/assets/<filename>", methods=["GET"])
async def serve_asset(request, filename):
    safe = filename.replace("..", "").replace("/", "").replace("\\", "")
    _mime = {".gif": "image/gif", ".png": "image/png", ".ico": "image/x-icon"}
    ext = ""
    parts = safe.rsplit(".", 1)
    if len(parts) == 2:
        ext = "." + parts[1]
    ct = _mime.get(ext, "application/octet-stream")
    for prefix in ("/web/assets/", "/assets/"):
        path = prefix + safe
        try:
            os.stat(path)
            with open(path, "rb") as f:
                body = f.read()
            return body, 200, {"Content-Type": ct, "Cache-Control": "public, max-age=3600"}
        except OSError:
            continue
    return _error("Not found", 404)


# ---------------------------------------------------------------------------
# /api/status
# ---------------------------------------------------------------------------

@app.route("/api/status", methods=["GET"])
async def get_status(request):
    cfg = config_manager.get_config()
    zones = watering.get_all_status()
    lights = []
    for i in range(cfg.get("num_lights", 3)):
        lights.append(schedule.get_light_status(i))
    relay_states = relay.get_states()
    return _json({
        "zones": zones,
        "lights": lights,
        "relays": relay_states,
        "uptime_s": time.ticks_diff(time.ticks_ms(), _boot_ticks) // 1000,
    })


# ---------------------------------------------------------------------------
# /api/water
# ---------------------------------------------------------------------------

@app.route("/api/water", methods=["POST"])
async def do_water(request):
    body = request.json or {}
    zone = int(body.get("zone", 0))
    result = await watering.manual_water(zone)
    status_code = 200 if result.get("status") == "ok" else 409
    return _json(result, status_code)


# ---------------------------------------------------------------------------
# /api/diagnostic
# ---------------------------------------------------------------------------

@app.route("/api/diagnostic/start", methods=["GET", "POST"])
async def diag_start(request):
    moisture.diag_start()
    return _json({"status": "ok", "message": "Logging started."})

@app.route("/api/diagnostic/stop", methods=["GET", "POST"])
async def diag_stop(request):
    moisture.diag_stop()
    return _json({"status": "ok", "entries": moisture.diag_get_count()})

@app.route("/api/diagnostic/status", methods=["GET"])
async def diag_status(request):
    return _json({
        "active": moisture.diag_is_active(),
        "entries": moisture.diag_get_count(),
    })

@app.route("/api/diagnostic/download", methods=["GET"])
async def diag_download(request):
    csv = moisture.diag_get_csv()
    return csv, 200, {"Content-Type": "text/csv",
                      "Content-Disposition": "attachment; filename=diag.csv"}


# ---------------------------------------------------------------------------
# /api/light/mode
# ---------------------------------------------------------------------------

@app.route("/api/light/mode", methods=["POST"])
async def set_light_mode(request):
    body = request.json or {}
    index = int(body.get("index", 0))
    mode = body.get("mode", "schedule")
    if mode not in ("schedule", "skip", "manual"):
        return _error("Invalid mode. Use schedule, skip, or manual.")
    schedule.set_light_mode(index, mode)
    return _json({"status": "ok", "index": index, "mode": mode})


# ---------------------------------------------------------------------------
# /api/config
# ---------------------------------------------------------------------------

@app.route("/api/config", methods=["GET"])
async def get_config(request):
    cfg = config_manager.get_config()
    wifi = config_manager.get_wifi()
    import network
    wlan = network.WLAN(network.STA_IF)
    ip = wlan.ifconfig()[0] if wlan.isconnected() else ""

    zones_info = []
    for z in cfg.get("zones", []):
        zones_info.append({
            "label": z.get("label", ""),
            "moisture_threshold": z.get("moisture_threshold", 30),
            "auto_water": z.get("auto_water", True),
            "skip": z.get("skip", False),
            "min_interval_min": z.get("min_interval_min", 60),
            "flow_rate_mlpm": z.get("flow_rate_mlpm", 100),
            "delivery_ml": z.get("delivery_ml", 250),
            "sensor_addr": z.get("sensor_addr", 0x36),
            "adc_dry": z.get("adc_dry", 55000),
            "adc_wet": z.get("adc_wet", 25000),
        })

    lights_info = []
    for lt in cfg.get("lights", []):
        lights_info.append({
            "label": lt.get("label", ""),
            "control_mode": lt.get("control_mode", "schedule"),
        })

    return _json({
        "num_zones":         cfg.get("num_zones", 3),
        "num_lights":        cfg.get("num_lights", 3),
        "relay_active_high": cfg.get("relay_active_high", False),
        "sensor_type":       cfg.get("sensor_type", "lm393"),
        "poll_interval_s":   cfg.get("poll_interval_s", 60),
        "zones":             zones_info,
        "lights":            lights_info,
        "version":           FIRMWARE_VERSION,
        "build_date":        BUILD_DATE,
        "uptime_s":          time.ticks_diff(time.ticks_ms(), _boot_ticks) // 1000,
        "wifi_ssid":         wifi.get("ssid", ""),
        "wifi_ip":           ip,
        "wifi_mode":         wifi.get("mode", "sta"),
    })


@app.route("/api/config", methods=["PUT"])
async def put_config(request):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")

    reboot_needed = False
    patch = {}

    if "num_zones" in body:
        nz = int(body["num_zones"])
        if 1 <= nz <= config_manager.MAX_ZONES:
            patch["num_zones"] = nz
            reboot_needed = True
    if "num_lights" in body:
        nl = int(body["num_lights"])
        if 0 <= nl <= config_manager.MAX_LIGHTS:
            patch["num_lights"] = nl
            reboot_needed = True
    if "relay_active_high" in body:
        patch["relay_active_high"] = bool(body["relay_active_high"])
        reboot_needed = True
    if "sensor_type" in body:
        st = body["sensor_type"]
        if st in ("lm393", "stemma"):
            patch["sensor_type"] = st
            if st == "stemma":
                patch["poll_interval_s"] = 5
            else:
                patch["poll_interval_s"] = 60
            reboot_needed = True
    if "poll_interval_s" in body:
        pi = int(body["poll_interval_s"])
        if 1 <= pi <= 3600:
            patch["poll_interval_s"] = pi
            reboot_needed = True

    if patch:
        config_manager.update_config(patch)

    if "zone_config" in body:
        zc = body["zone_config"]
        idx = int(zc.get("index", 0))
        zp = {}
        for key in ("label", "moisture_threshold",
                     "auto_water", "skip", "min_interval_min",
                     "flow_rate_mlpm", "delivery_ml",
                     "adc_dry", "adc_wet"):
            if key in zc:
                val = zc[key]
                if key in ("moisture_threshold", "min_interval_min",
                           "flow_rate_mlpm", "delivery_ml",
                           "adc_dry", "adc_wet"):
                    val = int(val)
                elif key in ("auto_water", "skip"):
                    val = bool(val)
                zp[key] = val
        if zp:
            config_manager.update_zone_config(idx, zp)
            if "adc_dry" in zp or "adc_wet" in zp:
                zcfg = config_manager.get_zone_config(idx)
                moisture.update_calibration(
                    idx,
                    zcfg.get("adc_dry", 55000),
                    zcfg.get("adc_wet", 25000),
                )

    if "light_config" in body:
        lc = body["light_config"]
        idx = int(lc.get("index", 0))
        lp = {}
        for key in ("label", "control_mode", "manual_state"):
            if key in lc:
                val = lc[key]
                if key == "manual_state":
                    val = bool(val)
                lp[key] = val
        if lp:
            config_manager.update_light_config(idx, lp)

    reboot = body.get("reboot", False) or (reboot_needed and body.get("apply", False))
    if reboot:
        asyncio.create_task(_delayed_reset(1000))

    return _json({"status": "ok", "rebooting": reboot})


# ---------------------------------------------------------------------------
# /api/schedules
# ---------------------------------------------------------------------------

@app.route("/api/schedules", methods=["GET"])
async def get_schedules(request):
    return _json(config_manager.get_schedules())


@app.route("/api/schedules", methods=["PUT"])
async def put_schedules(request):
    body = request.json
    if not isinstance(body, dict):
        return _error("Body must be a JSON object.")
    config_manager.save_schedules(body)
    return _json({"status": "ok"})


# ---------------------------------------------------------------------------
# /api/version
# ---------------------------------------------------------------------------

@app.route("/api/version", methods=["GET"])
async def get_version(request):
    return _json({"version": FIRMWARE_VERSION, "build_date": BUILD_DATE})


# ---------------------------------------------------------------------------
# /api/update  —  OTA firmware update
# ---------------------------------------------------------------------------

_OTA_MANIFEST = "ota_manifest.json"


@app.route("/api/ota/manifest", methods=["GET"])
async def get_ota_manifest(request):
    if _file_exists(_OTA_MANIFEST):
        try:
            with open(_OTA_MANIFEST, "r") as f:
                return _json(json.load(f))
        except Exception:
            pass
    return _json({})


@app.route("/api/ota/manifest", methods=["PUT"])
async def put_ota_manifest(request):
    try:
        body = request.json
        with open(_OTA_MANIFEST, "w") as f:
            json.dump(body, f)
        return _json({"status": "ok"})
    except Exception as e:
        return _error(str(e))


@app.route("/api/update", methods=["POST"])
async def ota_update(request):
    try:
        gc.collect()
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")

        filename = body.get("filename", "").strip().replace("\\", "/")
        content  = body.get("content",  "")
        reboot   = body.get("reboot",   False)
        append   = body.get("append",   False)

        _allowed_ext = (".py", ".html", ".css", ".js")
        if not any(filename.endswith(ext) for ext in _allowed_ext):
            return _error("File type not allowed.")
        if filename.startswith("/") or ".." in filename:
            return _error("Invalid path.")

        if not append and "/" in filename:
            acc = []
            for part in filename.split("/")[:-1]:
                acc.append(part)
                dirpath = "/".join(acc)
                try:
                    os.mkdir(dirpath)
                except OSError:
                    pass

        mode = "a" if append else "w"
        with open(filename, mode) as f:
            f.write(content)

        if not append:
            gz_stale = filename + ".gz"
            if _file_exists(gz_stale):
                try:
                    os.remove(gz_stale)
                except OSError:
                    pass

        print("[OTA] {} {} ({} bytes)".format(
            "Appended" if append else "Written", filename, len(content)))

        if reboot:
            asyncio.create_task(_delayed_reset(1500))

        return _json({"status": "ok", "filename": filename,
                      "bytes": len(content), "rebooting": reboot})
    except Exception as e:
        print("[OTA] Error: {}: {}".format(type(e).__name__, e))
        return _error("{}: {}".format(type(e).__name__, e))


async def _delayed_reset(ms):
    await asyncio.sleep_ms(ms)
    machine.reset()


# ---------------------------------------------------------------------------
# /api/wifi/reset
# ---------------------------------------------------------------------------

@app.route("/api/wifi/reset", methods=["POST"])
async def wifi_reset(request):
    config_manager.clear_wifi()
    asyncio.create_task(_delayed_reset(1000))
    return _json({"status": "rebooting"})


# ---------------------------------------------------------------------------
# Error handlers
# ---------------------------------------------------------------------------

@app.errorhandler(404)
async def not_found(request):
    return _error("Not found.", 404)


@app.errorhandler(413)
async def too_large(request):
    return _error("Request too large.", 413)


@app.errorhandler(500)
async def internal_error(request):
    return _error("Internal server error.", 500)


# ---------------------------------------------------------------------------
# Start
# ---------------------------------------------------------------------------

async def start():
    print("[Server] Grow Station v{} — starting on port 80".format(FIRMWARE_VERSION))
    await app.start_server(host="0.0.0.0", port=80)

"""
temperature.py
DS18B20 OneWire temperature sensor driver for MicroPython.

Scans the OneWire bus for DS18B20 devices and reads temperature per zone.
Multiple sensors share a single data pin (OneWire bus).
"""

import machine
import time

try:
    import onewire
    import ds18x20
    _HAS_ONEWIRE = True
except ImportError:
    _HAS_ONEWIRE = False

DS18B20_PIN = 3

_ds = None
_ow = None
_rom_list: list = []
_zone_map: list = []
_temps: list = []


def init(pin: int = DS18B20_PIN, num_zones: int = 3):
    """Initialize OneWire bus, scan for DS18B20 sensors, map to zones."""
    global _ds, _ow, _rom_list, _zone_map, _temps

    _zone_map = [None] * num_zones
    _temps = [None] * num_zones

    if not _HAS_ONEWIRE:
        print("[Temp] onewire/ds18x20 modules not available")
        return

    try:
        dat = machine.Pin(pin)
        _ow = onewire.OneWire(dat)
        _ds = ds18x20.DS18X20(_ow)
        _rom_list = _ds.scan()
        print(f"[Temp] DS18B20 bus on GP{pin}: found {len(_rom_list)} sensor(s)")
        for idx, rom in enumerate(_rom_list):
            rom_str = _rom_to_str(rom)
            print(f"[Temp]   [{idx}] {rom_str}")
            if idx < num_zones:
                _zone_map[idx] = rom
    except Exception as e:
        print(f"[Temp] Init error: {e}")
        _ds = None


def _rom_to_str(rom: bytes) -> str:
    return "-".join(f"{b:02x}" for b in rom)


def get_sensor_count() -> int:
    return len(_rom_list)


def get_sensor_ids() -> list:
    return [_rom_to_str(r) for r in _rom_list]


def read_all():
    """Trigger a conversion on all sensors and read results into cache."""
    global _temps
    if _ds is None or not _rom_list:
        return
    try:
        _ds.convert_temp()
        time.sleep_ms(750)
        for i, rom in enumerate(_zone_map):
            if rom is None:
                continue
            try:
                temp_c = _ds.read_temp(rom)
                if i < len(_temps):
                    _temps[i] = round(temp_c, 1)
            except Exception:
                if i < len(_temps):
                    _temps[i] = None
    except Exception as e:
        print(f"[Temp] Read error: {e}")


def get_temp_c(zone: int):
    """Return cached temperature in Celsius for a zone, or None."""
    if zone < len(_temps):
        return _temps[zone]
    return None


def get_temp_f(zone: int):
    """Return cached temperature in Fahrenheit for a zone, or None."""
    c = get_temp_c(zone)
    if c is None:
        return None
    return round(c * 9.0 / 5.0 + 32.0, 1)


def is_available() -> bool:
    return _ds is not None and len(_rom_list) > 0

/* Grow Station — Frontend */

const OTA_MANIFEST_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/growstation/manifest.json';
const OTA_BUNDLE_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/growstation/bundle.json';
const OTA_CHANGELOG_URL =
  'https://raw.githubusercontent.com/keglevelmonitor/keglevelpico/main/ota/growstation/changelog.json';

let numZones = 3;
let numLights = 3;
let sensorType = 'lm393';
let pollTimer = null;
let connected = false;
let consecutiveFailures = 0;
const OFFLINE_AFTER_FAILURES = 3;

let _otaManifest = null;
let _otaBundle = null;
let _lastWifiMode = 'sta';
let _activeSettingsTab = 'system';

const DAY_NAMES = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

// =========================================================================
// API helpers
// =========================================================================

async function apiFetch(path, opts = {}, timeoutMs = 4000) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const resp = await fetch(path, { ...opts, signal: controller.signal });
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    return await resp.json();
  } finally {
    clearTimeout(timeout);
  }
}

// =========================================================================
// Screen / nav management
// =========================================================================

function showScreen(id) {
  document.querySelectorAll('.screen').forEach(el => el.classList.add('hidden'));
  const screen = document.getElementById(id);
  if (screen) screen.classList.remove('hidden');
}

function setActiveNav(activeId) {
  document.querySelectorAll('.top-nav .nav-btn').forEach(b => b.classList.remove('active'));
  const btn = document.getElementById(activeId);
  if (btn) btn.classList.add('active');
}

function navigateToDashboard() {
  showScreen('dashboard-screen');
  setActiveNav('btn-nav-dashboard');
  stopWateringPoll();
  startPolling();
}

function navigateToSettings() {
  showScreen('settings-screen');
  setActiveNav('btn-nav-settings');
  stopPolling();
  setActiveSettingsTab('system');
  loadSystemInfo();
}

function setActiveSettingsTab(tabId) {
  _activeSettingsTab = tabId;
  stopWateringPoll();
  document.querySelectorAll('.settings-tab-btn').forEach(b => b.classList.remove('active'));
  document.querySelectorAll('.settings-pane').forEach(p => p.classList.remove('active'));
  const btn = document.querySelector('.settings-tab-btn[data-settings-tab="' + tabId + '"]');
  const pane = document.getElementById('settings-' + tabId);
  if (btn) btn.classList.add('active');
  if (pane) pane.classList.add('active');
  if (tabId === 'watering') renderWateringSettings();
  if (tabId === 'schedules') renderScheduleSettings();
}

// =========================================================================
// Polling
// =========================================================================

async function poll() {
  try {
    const data = await apiFetch('/api/status');
    updateDashboard(data);
    consecutiveFailures = 0;
    setConnected(true);
  } catch (_) {
    consecutiveFailures++;
    if (consecutiveFailures >= OFFLINE_AFTER_FAILURES) setConnected(false);
  }
}

function startPolling() {
  if (pollTimer) clearInterval(pollTimer);
  poll();
  pollTimer = setInterval(poll, 2000);
}

function stopPolling() {
  if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
}

function setConnected(ok) {
  connected = ok;
  document.getElementById('header-title').classList.toggle('disconnected', !ok);
}

// =========================================================================
// Dashboard rendering
// =========================================================================

function updateDashboard(data) {
  const zones = data.zones || [];
  zones.forEach(updateZoneCard);

  const lights = data.lights || [];
  lights.forEach(updateLightCard);

  applyNumZones(zones.length || numZones);
  applyNumLights(lights.length || numLights);
}

function updateZoneCard(z) {
  const i = z.zone;
  const card = document.getElementById('zone-card-' + i);
  if (!card) return;

  const labelEl = document.getElementById('zone-label-' + i);
  if (labelEl) labelEl.textContent = z.label || ('Watering Zone ' + (i + 1));

  const valEl = document.getElementById('moisture-value-' + i);
  if (valEl) {
    if (!z.sensor_ok || z.moisture_pct < 0) {
      valEl.textContent = '--';
    } else {
      valEl.textContent = z.moisture_pct.toFixed(0);
    }
  }

  const bar = document.getElementById('moisture-bar-' + i);
  if (bar) {
    const pct = Math.max(0, Math.min(100, z.moisture_pct || 0));
    bar.style.width = (z.sensor_ok ? pct : 0) + '%';
    bar.className = 'moisture-bar-fill';
    if (z.sensor_ok && z.moisture_pct >= 0) {
      if (pct < 20) bar.classList.add('dry');
      else if (pct < 35) bar.classList.add('low');
      else if (pct < 75) bar.classList.add('good');
      else bar.classList.add('wet');
    }
  }

  const tempEl = document.getElementById('zone-temp-' + i);
  if (tempEl) {
    tempEl.textContent = z.temp_f != null ? z.temp_f.toFixed(1) + ' °F' : '--';
  }

  const lastEl = document.getElementById('zone-last-watered-' + i);
  if (lastEl) {
    if (z.last_watered && z.last_watered > 0) {
      lastEl.textContent = formatTimestamp(z.last_watered);
    } else {
      lastEl.textContent = 'Never';
    }
  }

  card.classList.toggle('zone-skipped', !!z.skip);

  const autoBtn = document.getElementById('btn-auto-' + i);
  if (autoBtn) autoBtn.classList.toggle('active', !!z.auto_water);

  const skipBtn = document.getElementById('btn-zone-skip-' + i);
  if (skipBtn) skipBtn.classList.toggle('active', !!z.skip);

  const waterBadge = document.getElementById('zone-watering-badge-' + i);
  if (waterBadge) waterBadge.classList.toggle('badge-hidden', !z.watering_now);

  const waterBtn = document.getElementById('btn-water-' + i);
  if (waterBtn) waterBtn.disabled = z.watering_now || z.skip;
}

function updateLightCard(lt) {
  const i = lt.index;
  const card = document.getElementById('light-card-' + i);
  if (!card) return;

  const labelEl = document.getElementById('light-label-' + i);
  if (labelEl) labelEl.textContent = lt.label || ('Lighting Zone ' + (i + 1));

  const display = document.getElementById('light-display-' + i);
  if (display) {
    const textEl = display.querySelector('.light-on-off-text');
    if (textEl) textEl.textContent = lt.is_on ? 'ON' : 'OFF';
    display.classList.toggle('is-on', lt.is_on);
  }

  const nextEl = document.getElementById('light-next-' + i);
  if (nextEl) nextEl.textContent = lt.next_event || '--';

  const mode = lt.op_mode || 'schedule';
  const schedBtn = document.getElementById('btn-light-sched-' + i);
  const skipBtn = document.getElementById('btn-light-skip-' + i);
