var _calInProgress = false;

function runCalibration(index, type) {
  if (_calInProgress) return;
  _calInProgress = true;

  var btn = document.getElementById('wz-cal-' + type + '-btn-' + index);
  var bar = document.getElementById('wz-cal-bar-' + index);
  var barFill = document.getElementById('wz-cal-bar-fill-' + index);
  var barLabel = document.getElementById('wz-cal-bar-label-' + index);
  var targetEl = document.getElementById('wz-adc-' + type + '-' + index);

  var CAL_SAMPLES = 3;
  var CAL_INTERVAL_MS = 5000;
  var samples = [];
  var elapsed = 0;
  var totalMs = CAL_SAMPLES * CAL_INTERVAL_MS;

  if (btn) { btn.textContent = 'Sampling...'; btn.disabled = true; }
  if (bar) bar.classList.remove('hidden');
  if (barFill) barFill.style.width = '0%';
  if (barLabel) barLabel.textContent = 'Sampling... 0/' + CAL_SAMPLES;

  var progressTimer = setInterval(function() {
    elapsed += 200;
    var pct = Math.min(100, (elapsed / totalMs) * 100);
    if (barFill) barFill.style.width = pct + '%';
  }, 200);

  var sampleCount = 0;
  function takeSample() {
    apiFetch('/api/status').then(function(data) {
      var zones = data.zones || [];
      var z = zones[index];
      if (z && z.moisture_raw != null) {
        samples.push(z.moisture_raw);
      }
      sampleCount++;
      if (barLabel) barLabel.textContent = 'Sampling... ' + sampleCount + '/' + CAL_SAMPLES;

      if (sampleCount < CAL_SAMPLES) {
        setTimeout(takeSample, CAL_INTERVAL_MS);
      } else {
        clearInterval(progressTimer);
        if (barFill) barFill.style.width = '100%';

        var avg = Math.round(samples.reduce(function(a, b) { return a + b; }, 0) / samples.length);
        if (targetEl) targetEl.value = avg;
        if (barLabel) barLabel.textContent = type.toUpperCase() + ' captured: ' + avg;

        setTimeout(function() {
          if (bar) bar.classList.add('hidden');
          if (btn) { btn.textContent = 'CAL ' + type.toUpperCase(); btn.disabled = false; }
          _calInProgress = false;
        }, 2000);
      }
    }).catch(function() {
      sampleCount++;
      if (sampleCount < CAL_SAMPLES) {
        setTimeout(takeSample, CAL_INTERVAL_MS);
      } else {
        clearInterval(progressTimer);
        if (bar) bar.classList.add('hidden');
        if (btn) { btn.textContent = 'CAL ' + type.toUpperCase(); btn.disabled = false; }
        _calInProgress = false;
      }
    });
  }

  takeSample();
}

