async function checkForUpdates() {
  const statusEl = document.getElementById('update-status');
  const installBtn = document.getElementById('btn-install-update');
  if (_lastWifiMode === 'ap') {
    statusEl.textContent = 'Firmware updates are not available in Standalone mode.';
    return;
  }
  statusEl.textContent = 'Checking...';
  installBtn.classList.add('hidden');
  try {
    const cfg = await apiFetch('/api/config');
    const currentVer = cfg.version || '0.0.0';
    document.getElementById('upd-current-ver').textContent = currentVer;

    const resp = await fetch(OTA_MANIFEST_URL, { cache: 'no-store' });
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    _otaManifest = await resp.json();
    const latestVer = _otaManifest.version || '0.0.0';
    document.getElementById('upd-latest-ver').textContent = latestVer;

    if (_compareVersions(latestVer, currentVer) > 0) {
      statusEl.textContent = 'Update available: v' + latestVer;
      installBtn.classList.remove('hidden');
    } else {
      statusEl.textContent = 'You are up to date.';
    }
    loadChangelog();
    loadWhatsNew(currentVer);
  } catch (e) {
    statusEl.textContent = 'Check failed: ' + (e.message || e);
  }
}

function _compareVersions(a, b) {
  const pa = a.split('.').map(Number);
  const pb = b.split('.').map(Number);
  for (let i = 0; i < 3; i++) {
    const va = pa[i] || 0, vb = pb[i] || 0;
    if (va > vb) return 1;
    if (va < vb) return -1;
  }
  return 0;
}

async function loadChangelog() {
  const container = document.getElementById('changelog-list');
  try {
    const resp = await fetch(OTA_CHANGELOG_URL, { cache: 'no-store' });
    if (!resp.ok) { container.innerHTML = '<p class="panel-note">No changelog available.</p>'; return; }
    const entries = await resp.json();
    if (!entries.length) { container.innerHTML = '<p class="panel-note">No changelog entries.</p>'; return; }
    container.innerHTML = entries.map(function(e) {
      return '<div class="changelog-entry">'
        + '<div class="changelog-entry-header">'
        + '<span class="changelog-ver">v' + e.version + '</span>'
        + '<span class="changelog-date">' + (e.date || '') + '</span></div>'
        + '<div class="changelog-notes">' + (e.notes || '').replace(/\n/g, '<br>') + '</div></div>';
    }).join('');
  } catch (_) {
    container.innerHTML = '<p class="panel-note">Failed to load changelog.</p>';
  }
}

async function loadWhatsNew(currentVer) {
  const container = document.getElementById('whats-new');
  try {
    const resp = await fetch(OTA_CHANGELOG_URL, { cache: 'no-store' });
    if (!resp.ok) { container.classList.add('hidden'); return; }
    const entries = await resp.json();
    const newer = (entries || []).filter(function(e) { return _compareVersions(e.version, currentVer) > 0; });
    if (!newer.length) { container.classList.add('hidden'); return; }
    container.classList.remove('hidden');
    container.innerHTML = '<div class="whats-new-title">What\'s New</div>'
      + newer.map(function(e) {
          return '<div class="whats-new-entry"><span class="whats-new-ver">v' + e.version + '</span>'
            + '<div class="whats-new-notes">' + (e.notes || '').replace(/\n/g, '<br>') + '</div></div>';
        }).join('');
  } catch (_) { container.classList.add('hidden'); }
}

async function installUpdate() {
  if (!_otaManifest) { alert('No update manifest loaded. Check first.'); return; }
  const statusEl = document.getElementById('update-status');
  const progressWrap = document.getElementById('update-progress');
  const progressBar = document.getElementById('update-bar-fill');
  const progressText = document.getElementById('update-progress-text');
  progressWrap.classList.remove('hidden');

  statusEl.textContent = 'Downloading firmware bundle...';
  progressBar.style.width = '5%';
  try {
    const resp = await fetch(OTA_BUNDLE_URL, { cache: 'no-store' });
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    _otaBundle = await resp.json();
  } catch (e) {
    statusEl.textContent = 'Download failed: ' + (e.message || e);
    progressWrap.classList.add('hidden');
    return;
  }

  const OTA_CHUNK = 8192;
  const allFiles = _otaBundle.files || [];

  let oldHashes = {};
  try {
    const installed = await apiFetch('/api/ota/manifest');
    if (installed && installed.files) {
      installed.files.forEach(function(f) { oldHashes[f.path] = f.sha256; });
    }
  } catch (_) {}

  const files = allFiles.filter(function(f) {
    const oldHash = oldHashes[f.path];
    const newEntry = (_otaManifest.files || []).find(function(mf) { return mf.path === f.path; });
    const newHash = newEntry ? newEntry.sha256 : null;
    return !oldHash || !newHash || oldHash !== newHash;
  });

  const skipped = allFiles.length - files.length;
  if (skipped > 0) statusEl.textContent = skipped + ' unchanged file(s) skipped.';

  const total = files.length;
  if (total === 0) {
    statusEl.textContent = 'All files are already up to date.';
    progressWrap.classList.add('hidden');
    return;
  }
  statusEl.textContent = 'Installing ' + total + ' file(s)...';

  for (let i = 0; i < total; i++) {
    const f = files[i];
    const isLast = i === total - 1;
    const pct = Math.round(((i + 1) / total) * 100);
    progressBar.style.width = pct + '%';
    progressText.textContent = f.path + ' (' + (i + 1) + '/' + total + ')';

    const dest = f.path.startsWith('www/') ? 'web/' + f.path.slice(4) : f.path;

    const chunks = [];
    if (f.content.length > OTA_CHUNK) {
      for (let off = 0; off < f.content.length; off += OTA_CHUNK) {
        chunks.push(f.content.substring(off, off + OTA_CHUNK));
      }
    } else {
      chunks.push(f.content);
    }

    if (isLast) {
      const lastIdx = chunks.length - 1;
      for (let c = 0; c < lastIdx; c++) {
        try {
          await apiFetch('/api/update', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ filename: dest, content: chunks[c], append: c > 0, reboot: false }),
          }, 15000);
        } catch (e) {
          statusEl.textContent = 'Failed on ' + f.path + ': ' + (e.message || e);
          return;
        }
      }
      try {
        await apiFetch('/api/ota/manifest', {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(_otaManifest),
        }, 15000);
      } catch (_) {}
      try {
        await apiFetch('/api/update', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ filename: dest, content: chunks[lastIdx], append: lastIdx > 0, reboot: true }),
        }, 15000);
      } catch (e) {
        statusEl.textContent = 'Failed on ' + f.path + ': ' + (e.message || e);
        return;
      }
    } else {
      for (let c = 0; c < chunks.length; c++) {
        try {
          await apiFetch('/api/update', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ filename: dest, content: chunks[c], append: c > 0, reboot: false }),
          }, 15000);
        } catch (e) {
          statusEl.textContent = 'Failed on ' + f.path + ': ' + (e.message || e);
          return;
        }
      }
    }
  }

  statusEl.textContent = 'Update complete. Rebooting...';
  progressBar.style.width = '100%';
  progressText.textContent = 'Waiting for reboot...';

  const expectedVer = _otaManifest ? (_otaManifest.version || null) : null;
  await _waitForReboot(expectedVer, statusEl, progressWrap, progressText);
}

async function _waitForReboot(expectedVer, statusEl, progressWrap, progressText) {
  await new Promise(function(r) { setTimeout(r, 4000); });
  for (let i = 0; i < 10; i++) {
    try {
      const res = await fetch('/api/version', { signal: AbortSignal.timeout(3000) });
      if (res.ok) {
        const data = await res.json();
        const newVer = data.version || '?';
        document.getElementById('upd-current-ver').textContent = newVer;
        if (expectedVer && newVer === expectedVer) {
          statusEl.textContent = 'Update complete! Now running v' + newVer + '.';
        } else {
          statusEl.textContent = 'Pico is back online (v' + newVer + ').';
        }
        progressWrap.classList.add('hidden');
        return;
      }
    } catch (_) {}
    if (i < 9) {
      progressText.textContent = 'Waiting for reboot... (' + (i + 2) + '/10)';
      await new Promise(function(r) { setTimeout(r, 3000); });
    }
  }
  statusEl.textContent = 'Pico did not respond after reboot. Try RELOAD or check manually.';
  progressWrap.classList.add('hidden');
}

async function reloadPage() {
  const files = ['/', '/app.js', '/style.css'];
  await Promise.all(files.map(function(f) { return fetch(f, { cache: 'reload' }).catch(function() {}); }));
  if ('caches' in window) {
    try {
      const names = await caches.keys();
      await Promise.all(names.map(function(n) { return caches.delete(n); }));
    } catch (_) {}
  }
  window.location.reload();
}

// =========================================================================
// Helpers
// =========================================================================

function formatTimestamp(epochSec) {
  if (!epochSec || epochSec <= 0) return 'Never';
  const d = new Date(epochSec * 1000);
  const now = new Date();
  const diffMs = now - d;
  if (diffMs < 60000) return 'Just now';
  if (diffMs < 3600000) return Math.floor(diffMs / 60000) + 'm ago';
  if (diffMs < 86400000) return Math.floor(diffMs / 3600000) + 'h ago';
  return d.toLocaleDateString();
}

// =========================================================================
// Init & config
// =========================================================================

async function loadConfig() {
  try {
    const cfg = await apiFetch('/api/config');
    if (cfg.version) {
      document.getElementById('footer-version').textContent = 'Grow Station v' + cfg.version;
    }
    numZones = cfg.num_zones || 3;
    numLights = cfg.num_lights || 3;
    sensorType = cfg.sensor_type || 'lm393';
    applyNumZones(numZones);
    applyNumLights(numLights);
    updateApModeNotice(cfg.wifi_mode);
  } catch (_) {}
}

// =========================================================================
// Event wiring
// =========================================================================

document.addEventListener('DOMContentLoaded', function() {
  // Nav
  document.getElementById('btn-nav-dashboard').addEventListener('click', navigateToDashboard);
  document.getElementById('btn-nav-settings').addEventListener('click', navigateToSettings);

  // Help
  document.getElementById('btn-help').addEventListener('click', function() {
    let anchor = 'toc';
    const activeNav = document.querySelector('.top-nav .nav-btn.active');
    if (activeNav) {
      const id = activeNav.id;
      if (id === 'btn-nav-dashboard') {
        anchor = 'dashboard';
      } else if (id === 'btn-nav-settings') {
        const tab = document.querySelector('.settings-tab-btn.active');
        const t = tab ? tab.dataset.settingsTab : '';
        if (t === 'system') anchor = 'system';
        else if (t === 'watering') anchor = 'watering';
        else if (t === 'schedules') anchor = 'schedules';
        else if (t === 'updates') anchor = 'updates';
        else if (t === 'about') anchor = 'about';
        else anchor = 'system';
      }
    }
    window.open('help.html#' + anchor, '_blank');
  });

  // Settings tabs
  document.querySelectorAll('.settings-tab-btn').forEach(function(btn) {
    btn.addEventListener('click', function() { setActiveSettingsTab(btn.dataset.settingsTab); });
  });

  // Zone buttons (AUTO / SKIP / WATER)
  for (let idx = 0; idx < 3; idx++) {
    const autoBtn = document.getElementById('btn-auto-' + idx);
    if (autoBtn) autoBtn.addEventListener('click', (function(i) { return function() { toggleAutoWater(i); }; })(idx));
    const skipBtn = document.getElementById('btn-zone-skip-' + idx);
    if (skipBtn) skipBtn.addEventListener('click', (function(i) { return function() { toggleZoneSkip(i); }; })(idx));
    const waterBtn = document.getElementById('btn-water-' + idx);
    if (waterBtn) waterBtn.addEventListener('click', (function(i) { return function() { doWater(i); }; })(idx));
  }

  // Light mode buttons (SCHED / SKIP / MAN)
  for (let idx = 0; idx < 3; idx++) {
    const schedBtn = document.getElementById('btn-light-sched-' + idx);
    const skipBtn = document.getElementById('btn-light-skip-' + idx);
    const manBtn = document.getElementById('btn-light-man-' + idx);
    if (schedBtn) schedBtn.addEventListener('click', (function(i) { return function() { setLightMode(i, 'schedule'); }; })(idx));
    if (skipBtn) skipBtn.addEventListener('click', (function(i) { return function() { setLightMode(i, 'skip'); }; })(idx));
    if (manBtn) manBtn.addEventListener('click', (function(i) { return function() { setLightMode(i, 'manual'); }; })(idx));
  }

  // System settings
  document.getElementById('sys-sensor-type').addEventListener('change', function() {
    saveSystemSetting('sensor_type', this.value);
  });
  document.getElementById('sys-num-zones').addEventListener('change', function() {
    saveSystemSetting('num_zones', parseInt(this.value, 10));
  });
  document.getElementById('sys-num-lights').addEventListener('change', function() {
    saveSystemSetting('num_lights', parseInt(this.value, 10));
  });
  document.getElementById('sys-relay-polarity').addEventListener('change', function() {
    saveSystemSetting('relay_active_high', this.value === 'high');
  });
  document.getElementById('sys-poll-interval').addEventListener('change', function() {
    saveSystemSetting('poll_interval_s', parseInt(this.value, 10));
  });

  // WiFi mode switch
  document.getElementById('btn-enable-wifi').addEventListener('click', function() {
    document.getElementById('wifi-reset-msg').textContent =
      'This will switch the Pico to Network mode. It will reboot into setup mode where you can enter your WiFi network credentials.';
    document.getElementById('modal-wifi-reset').classList.remove('hidden');
  });
  document.getElementById('btn-enable-standalone').addEventListener('click', function() {
    document.getElementById('wifi-reset-msg').textContent =
      'This will switch the Pico to Standalone mode. It will create its own WiFi network (GrowStation). Internet access, firmware updates will not be available.';
    document.getElementById('modal-wifi-reset').classList.remove('hidden');
  });
  document.getElementById('btn-wifi-reset-cancel').addEventListener('click', function() {
    document.getElementById('modal-wifi-reset').classList.add('hidden');
  });
  document.getElementById('btn-wifi-reset-confirm').addEventListener('click', async function() {
    const btn = document.getElementById('btn-wifi-reset-confirm');
    btn.disabled = true;
    btn.textContent = 'Rebooting\u2026';
    try { await apiFetch('/api/wifi/reset', { method: 'POST' }); } catch (_) {}
    document.getElementById('wifi-reset-msg').textContent =
      'Pico is rebooting into setup mode. Connect to the GrowStation WiFi network to continue.';
  });

  // Updates
  document.getElementById('btn-check-update').addEventListener('click', checkForUpdates);
  document.getElementById('btn-install-update').addEventListener('click', installUpdate);
  document.getElementById('btn-reload').addEventListener('click', reloadPage);

  // Boot
  loadConfig();
  startPolling();
});

