  border-radius: 4px;
  color: #e0e0e0;
  text-align: center;
}

.cal-progress {
  margin: 8px 0;
}

.cal-progress-label {
  font-size: 12px;
  color: #4caf50;
  margin-bottom: 4px;
  text-align: center;
}

.cal-progress-track {
  height: 8px;
  background: #222;
  border-radius: 4px;
  overflow: hidden;
}

.cal-progress-fill {
  height: 100%;
  width: 0%;
  background: #4caf50;
  border-radius: 4px;
  transition: width 0.2s linear;
}

.save-zone-btn {
  padding: 10px 24px;
  font-size: 13px;
  font-weight: 700;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #ffa500;
  color: #1e1e1e;
  margin-top: 8px;
}

.save-zone-btn:hover { background: #ffb833; }

.day-row {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 0;
  flex-wrap: wrap;
}

.day-label {
  font-size: 13px;
  color: #888;
  min-width: 32px;
}

.day-row input[type="time"] {
  padding: 6px 8px;
  font-size: 13px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 4px;
  color: #e0e0e0;
}

.day-row .time-sep {
  font-size: 13px;
  color: #555;
}

.save-schedule-btn {
  padding: 10px 24px;
  font-size: 13px;
  font-weight: 700;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #ffa500;
  color: #1e1e1e;
  margin-top: 12px;
}

.save-schedule-btn:hover { background: #ffb833; }

/* ------------------------------------------------------------------ */
/* Panels                                                             */
/* ------------------------------------------------------------------ */
.panel-note {
  font-size: 13px;
  color: #777;
  line-height: 1.6;
  margin-bottom: 14px;
}

.profile-btn {
  padding: 10px 16px;
  font-size: 13px;
  font-weight: 700;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #2a2a2a;
  color: #e0e0e0;
  white-space: nowrap;
}

.profile-btn:hover { background: #3a3a3a; }

/* Readout bar */
.readout-bar {
  width: 100%;
  height: 8px;
  background: #333;
  border-radius: 4px;
  overflow: hidden;
  margin: 8px 0 14px;
}

.readout-bar-fill {
  height: 100%;
  background: #ffa500;
  border-radius: 4px;
  transition: width 0.3s ease;
  width: 0%;
}

/* ------------------------------------------------------------------ */
/* What's new / Changelog                                             */
/* ------------------------------------------------------------------ */
.whats-new {
  background: #1a1a1a;
  border-radius: 8px;
  padding: 12px 16px;
  margin: 12px 0;
}

.whats-new-title {
  font-size: 13px;
  font-weight: 700;
  color: #ffa500;
  margin-bottom: 8px;
}

.whats-new-entry { padding: 4px 0; border-bottom: 1px solid #222; }
.whats-new-entry:last-child { border-bottom: none; }
.whats-new-ver { font-size: 12px; font-weight: 700; color: #ccc; }
.whats-new-notes { font-size: 13px; color: #aaa; line-height: 1.4; margin-top: 2px; }

.update-actions {
  display: flex;
  gap: 10px;
  margin: 12px 0;
}

.update-btn-reload {
  padding: 10px 16px;
  font-size: 13px;
  font-weight: 700;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  background: #f59e0b;
  color: #1a1a1a;
  white-space: nowrap;
}

.update-btn-reload:hover:not(:disabled) { background: #fbbf24; }
.update-btn-reload:disabled { opacity: 0.5; cursor: not-allowed; }

.update-status { font-size: 13px; color: #888; margin-top: 8px; }
.update-progress-text { font-size: 12px; color: #888; margin-top: 4px; text-align: center; }

.changelog-list { max-height: 300px; overflow-y: auto; }
.changelog-entry { padding: 8px 0; border-bottom: 1px solid #1e1e1e; }
.changelog-entry-header { display: flex; justify-content: space-between; margin-bottom: 4px; }
.changelog-ver { font-size: 13px; font-weight: 700; color: #ffa500; }
.changelog-date { font-size: 12px; color: #555; }
.changelog-notes { font-size: 13px; color: #aaa; line-height: 1.5; }

/* ------------------------------------------------------------------ */
/* About section                                                      */
/* ------------------------------------------------------------------ */
.about-section { margin-bottom: 24px; }

.about-support-row {
  display: flex;
  align-items: flex-start;
  gap: 24px;
}

.about-support-row > div { flex: 1; min-width: 0; }

.about-support-img {
  width: 140px;
  height: 140px;
  object-fit: contain;
  flex-shrink: 0;
}

.about-section h3 { margin: 0 0 8px 0; font-size: 16px; color: #ffa500; }
.about-section p { margin: 0; font-size: 14px; color: #ccc; line-height: 1.5; }
.about-section a { color: #93c5fd; text-decoration: none; }
.about-section a:hover { text-decoration: underline; }

/* ------------------------------------------------------------------ */
/* Modal                                                              */
/* ------------------------------------------------------------------ */
.modal {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.modal.hidden { display: none; }

.modal-content {
  position: relative;
  background: #1a1a1a;
  border: 1px solid #444;
  border-radius: 10px;
  padding: 24px;
  width: 90%;
  max-width: 400px;
}

.modal-confirm p { margin: 0 0 20px 0; color: #e0e0e0; }

.modal-actions {
  display: flex;
  gap: 12px;
  justify-content: flex-end;
  margin-top: 20px;
}

.modal-actions .btn-cancel,
.modal-actions .btn-delete {
  padding: 10px 20px;
  font-size: 14px;
  font-weight: 600;
  border-radius: 4px;
  cursor: pointer;
}

.modal-actions .btn-cancel { background: #333; color: #ccc; border: 1px solid #444; }
.modal-actions .btn-cancel:hover { background: #444; }
.modal-actions .btn-delete { background: #991b1b; color: #fff; border: none; }
.modal-actions .btn-delete:hover { background: #b91c1c; }

/* ------------------------------------------------------------------ */
/* WiFi mode section                                                  */
/* ------------------------------------------------------------------ */
.wifi-mode-section {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid #333;
}

.wifi-mode-section > label {
  display: block;
  font-size: 13px;
  color: #aaa;
  margin-bottom: 10px;
}

.wifi-mode-buttons { display: flex; gap: 8px; }

.btn-wifi-reset {
  padding: 6px 16px;
  font-size: 13px;
  font-weight: 600;
  background: #4a1515;
  color: #f87171;
  border: 1px solid #6b2020;
  border-radius: 4px;
  cursor: pointer;
  flex: 1;
}

.btn-wifi-reset:hover:not(:disabled) { background: #6b2020; }
.btn-wifi-reset:disabled { background: #333; color: #888; border-color: #444; cursor: default; }

/* AP mode notice */
.ap-notice {
  background: #1a1a2e;
  border-left: 3px solid #ffc107;
  padding: 10px 14px;
  border-radius: 4px;
  margin-bottom: 16px;
  font-size: 13px;
  color: #ddd;
}

/* ------------------------------------------------------------------ */
/* Footer                                                             */
/* ------------------------------------------------------------------ */
.main-footer {
  text-align: center;
  padding: 20px;
  font-size: 12px;
  color: #444;
}

/* ------------------------------------------------------------------ */
/* Responsive                                                         */
/* ------------------------------------------------------------------ */
@media (min-width: 620px) {
  .zone-cards, .light-cards, .settings-cards {
    flex-direction: row;
    flex-wrap: wrap;
  }
  .zone-card, .light-card, .settings-card {
    flex: 1;
    min-width: 280px;
    border: 1px solid #222;
    border-radius: 10px;
    margin: 6px;
  }
}

@media (max-width: 380px) {
  .moisture-value { font-size: 36px; }
  .settings-tab-btn { padding: 8px 10px; font-size: 12px; }
}
